import java.io.*;
import java.util.*;
import org.owasp.encoder.Encode;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Sanitize and escape user input before outputting
        String sanitizedName = Encode.forHtml(name); // Using OWASP Encoder for HTML encoding

        System.out.println("Hello, " + sanitizedName + "!");

        // Now the user input 'name' is properly encoded to prevent XSS attacks
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
